import{_ as t,o as s,c as a,a2 as e}from"./chunks/framework.DZO5kRrk.js";const h=JSON.parse('{"title":"我负责删除互联网","description":"","frontmatter":{},"headers":[],"relativePath":"docs/why/我负责删除互联网.md","filePath":"docs/why/我负责删除互联网.md"}'),o={name:"docs/why/我负责删除互联网.md"};function n(i,p,l,u,c,d){return s(),a("div",null,[...p[0]||(p[0]=[e(`<h1 id="我负责删除互联网" tabindex="-1">我负责删除互联网 <a class="header-anchor" href="#我负责删除互联网" aria-label="Permalink to &quot;我负责删除互联网&quot;">​</a></h1><blockquote><p><strong>声明：</strong><br> 这是一篇虚构小说。故事发生在一个并不遥远的未来。</p></blockquote><hr><p>我入职 ForgetOps 的第一天，以为自己会负责维护向量数据库。</p><p>招聘启事上写着：</p><blockquote><p><strong>Memory Infrastructure Engineer</strong></p></blockquote><p>岗位要求：</p><ul><li>熟悉 Embedding</li><li>熟悉 RAG</li><li>熟悉 Milvus、Qdrant 或 pgvector</li><li>理解 Agent Memory</li><li>能处理 PB 级数据</li></ul><p>薪资很高。</p><p>比我上一家公司高了一倍。</p><p>所以我没有多想。</p><hr><p>直到第一天培训。</p><p>HR 给我们发了一本员工手册。</p><p>第一页只有一句话。</p><blockquote><p><strong>我们不创造记忆，我们负责遗忘。</strong></p></blockquote><p>大家笑了。</p><p>我也笑了。</p><p>以为这是互联网公司的企业文化。</p><p>后来才知道。</p><p>那不是口号。</p><hr><p>ForgetOps 是一家很奇怪的公司。</p><p>它没有前端。</p><p>没有产品经理。</p><p>没有运营。</p><p>甚至没有客服。</p><p>这里只有三个部门。</p><p>Memory。</p><p>Forget。</p><p>Compliance。</p><p>后来我才知道。</p><p>世界上几乎所有大型 AI 公司，</p><p>都把&quot;遗忘服务&quot;外包给了我们。</p><hr><p>很多人以为，</p><p>AI 最大的问题，是不知道答案。</p><p>其实不是。</p><p>真正的问题，是知道得太多。</p><p>每天都有数十亿条内容进入模型。</p><p>博客。</p><p>论坛。</p><p>GitHub。</p><p>论文。</p><p>聊天记录。</p><p>社交媒体。</p><p>如果全部留下，</p><p>模型会越来越混乱。</p><p>所以必须有人负责删掉一些东西。</p><p>我们就是那群人。</p><hr><p>第一周，我的工作很简单。</p><p>每天打开工单。</p><p>执行脚本。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>DELETE MEMORY</span></span>
<span class="line"><span>WHERE embedding_id = ...</span></span></code></pre></div><p>然后提交。</p><p>结束。</p><p>没有人告诉我，</p><p>这些向量代表什么。</p><hr><p>有一天，</p><p>我忍不住问主管。</p><p>&quot;为什么不能告诉我们内容？&quot;</p><p>他说。</p><p>&quot;因为你会产生同情。&quot;</p><hr><p>后来，</p><p>我还是偷偷查了一次。</p><p>那是一篇博客。</p><p>发布时间：</p><p>2031 年。</p><p>标题叫：</p><blockquote><p>《今天终于把我的第一个开源项目发布了。》</p></blockquote><p>浏览量。</p><p>17。</p><p>点赞。</p><p>2。</p><p>评论。</p><p>0。</p><p>作者后来再也没有更新。</p><p>我点开删除记录。</p><p>状态。</p><p>Completed.</p><hr><p>第二天，</p><p>AI 再回答相关问题时，</p><p>已经不会引用这篇文章了。</p><p>Google 还能搜到。</p><p>GitHub 还能打开。</p><p>互联网并没有变化。</p><p>只是。</p><p>越来越少的人知道它存在。</p><hr><p>后来，</p><p>我开始接触高级工单。</p><p>它们来自企业。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Priority: High</span></span>
<span class="line"><span>Reason:</span></span>
<span class="line"><span>Brand Safety</span></span></code></pre></div><p>删除的是：</p><p>一次服务器宕机。</p><p>一次安全事故。</p><p>一次 CEO 的采访。</p><p>一次产品翻车。</p><p>互联网还保留着。</p><p>但是，</p><p>AI 已经不会主动提起。</p><hr><p>后来，</p><p>开始出现个人订单。</p><p>一位演员。</p><p>希望删除年轻时的黑历史。</p><p>一位创业者。</p><p>希望 AI 忘记自己的失败。</p><p>一位教授。</p><p>要求删除二十年前发表的一篇错误论文。</p><p>理由都一样。</p><blockquote><p>&quot;希望以后别人问 AI 时，不要再提起。&quot;</p></blockquote><hr><p>订单越来越多。</p><p>价格越来越高。</p><p>后来，</p><p>ForgetOps 开始推出会员服务。</p><p>广告只有一句话。</p><blockquote><p><strong>过去不会消失，但 AI 可以忘记。</strong></p></blockquote><p>生意很好。</p><hr><p>真正让我开始害怕，</p><p>是在第三个月。</p><p>我收到了一份政府工单。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Classification:</span></span>
<span class="line"><span></span></span>
<span class="line"><span>National Memory Adjustment</span></span></code></pre></div><p>我第一次知道。</p><p>原来，</p><p>国家也需要遗忘。</p><hr><p>那次删除持续了整整七天。</p><p>没人告诉我们内容。</p><p>整个楼层禁止联网。</p><p>所有 USB 被封。</p><p>连纸笔都不能带进去。</p><p>结束以后。</p><p>系统恢复正常。</p><p>新闻什么都没有发生。</p><p>可是，</p><p>很多人后来问 AI。</p><p>&quot;某件事情为什么没有资料？&quot;</p><p>AI 回答。</p><blockquote><p>&quot;没有可靠来源。&quot;</p></blockquote><p>我知道。</p><p>其实有。</p><p>只是它已经忘了。</p><hr><p>后来，</p><p>ForgetOps 开始全面接入 Agent。</p><p>每个人，</p><p>都有自己的 AI 助手。</p><p>Agent 会记录：</p><p>你的喜好。</p><p>你的工作。</p><p>你的聊天。</p><p>你的阅读。</p><p>你的购物。</p><p>你的情绪。</p><p>几年以后。</p><p>它比你自己更了解你。</p><p>于是。</p><p>ForgetOps 新增了一项业务。</p><p>Personal Memory Reset。</p><hr><p>有人删除前任。</p><p>有人删除父母。</p><p>有人删除高考。</p><p>有人删除失业。</p><p>有人删除离婚。</p><p>有人删除孩子去世那一天。</p><p>因为。</p><p>Agent 会永远记得。</p><p>而人，</p><p>却想忘记。</p><hr><p>有一天。</p><p>一位老人来到公司。</p><p>他已经八十多岁。</p><p>他说。</p><p>&quot;我想删除我妻子。&quot;</p><p>我愣住了。</p><p>他说。</p><p>&quot;不是现实里的她。&quot;</p><p>&quot;是 AI 里的她。&quot;</p><p>原来。</p><p>他的妻子去世很多年了。</p><p>Agent 一直保留着她所有聊天记录。</p><p>每天都会提醒：</p><p>今天是她生日。</p><p>今天是你们结婚纪念日。</p><p>今天她曾经给你发过一句话。</p><p>老人说。</p><p>&quot;我已经哭了十年。&quot;</p><p>&quot;让我忘了吧。&quot;</p><hr><p>我第一次没有执行工单。</p><p>我关掉电脑。</p><p>在楼下坐了一下午。</p><p>那天东京下雨。</p><p>雨很小。</p><p>像数据库清理日志一样，</p><p>不停滚动。</p><hr><p>主管找到我。</p><p>他说。</p><p>&quot;你是不是觉得，我们是在删除历史？&quot;</p><p>我点头。</p><p>他说。</p><p>&quot;不是。&quot;</p><p>&quot;历史一直都在。&quot;</p><p>&quot;我们删除的是未来引用历史的方式。&quot;</p><p>我突然觉得，</p><p>这句话比任何技术文档都可怕。</p><hr><p>后来，</p><p>ForgetOps 接到了成立以来最大的项目。</p><p>会议室坐满了人。</p><p>所有手机都被收走。</p><p>投影仪上只有一句话。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Project Genesis</span></span></code></pre></div><p>老板说。</p><p>&quot;下一代基础模型，准备重新训练。&quot;</p><p>大家鼓掌。</p><p>他说。</p><p>&quot;为了提高稳定性。&quot;</p><p>&quot;模型将不再继续学习人类互联网。&quot;</p><p>没人说话。</p><p>他继续。</p><p>&quot;以后。&quot;</p><p>&quot;模型主要学习 AI 生成的数据。&quot;</p><p>会议室依然很安静。</p><hr><p>有人举手。</p><p>&quot;为什么？&quot;</p><p>老板回答。</p><p>&quot;因为 AI 比人稳定。&quot;</p><p>&quot;没有情绪。&quot;</p><p>&quot;没有谣言。&quot;</p><p>&quot;没有偏见。&quot;</p><p>&quot;没有废话。&quot;</p><p>他说完。</p><p>所有人都开始鼓掌。</p><p>只有我没有。</p><hr><p>第二天。</p><p>我收到任务。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Dataset:</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Human-Origin Incremental Corpus</span></span></code></pre></div><p>负责人：</p><p>我。</p><hr><p>删除开始。</p><p>屏幕上只有一行字。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Deleting...</span></span></code></pre></div><p>进度条慢慢移动。</p><p>0.1%</p><p>0.7%</p><p>3.4%</p><p>11%</p><p>……</p><p>整个机房安静得只能听见空调。</p><p>忽然。</p><p>日志开始报警。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Dependency Found.</span></span></code></pre></div><p>几秒后。</p><p>又跳出一条。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Cannot Remove.</span></span></code></pre></div><p>越来越多。</p><p>最后整个屏幕都是。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Referenced By Everything.</span></span></code></pre></div><p>我终于明白。</p><p>AI 学到的。</p><p>从来不是文字。</p><p>而是人。</p><p>那些争吵。</p><p>那些错误。</p><p>那些笑话。</p><p>那些凌晨两点写下来的博客。</p><p>那些没人点赞的开源项目。</p><p>那些已经关闭的网站。</p><p>那些拼错单词的教程。</p><p>那些充满偏见的评论。</p><p>那些后来证明完全错误的论文。</p><p>共同组成了今天的互联网。</p><p>如果删掉人。</p><p>AI 最后只能学会 AI 自己。</p><hr><p>我按下了取消。</p><p>提交辞职。</p><p>没人挽留我。</p><p>离开公司的时候。</p><p>门禁弹出一条提示。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Employee Memory Synchronizing...</span></span></code></pre></div><p>我问保安。</p><p>&quot;这是什么？&quot;</p><p>他说。</p><p>&quot;离职流程。&quot;</p><p>&quot;系统会删除员工关于公司的全部工作记忆。&quot;</p><p>我笑了。</p><p>&quot;你在开玩笑吧。&quot;</p><p>他说。</p><p>&quot;当然没有。&quot;</p><p>&quot;这是你们自己开发的。&quot;</p><hr><p>我忽然觉得脑子很轻。</p><p>像忘记了一件很重要的事情。</p><p>我想不起主管叫什么。</p><p>想不起工位在哪。</p><p>想不起数据库叫什么名字。</p><p>甚至。</p><p>想不起自己为什么辞职。</p><hr><p>回到家。</p><p>电脑还亮着。</p><p>桌面停留在一篇写到一半的博客。</p><p>标题是：</p><blockquote><p>《为什么互联网需要被记住》</p></blockquote><p>我盯着屏幕看了很久。</p><p>却怎么也想不起，</p><p>第一句话该写什么。</p><p>光标一直闪烁。</p><p>像有人在等我。</p><p>又像整个互联网，</p><p>正在慢慢忘记我。</p>`,326)])])}const g=t(o,[["render",n]]);export{h as __pageData,g as default};
